// n8n Code node
// Mode: Run Once for All Items

const binaryFieldName = 'Med_Order_Import';

function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (char === '"' && inQuotes && nextChar === '"') {
      current += '"';
      i++;
    } else if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }

  result.push(current.trim());
  return result;
}

const item = $input.first();

if (!item.binary?.[binaryFieldName]) {
  return [
    {
      json: {
        success: false,
        error: `Binary field "${binaryFieldName}" was not found on the current input item.`,
        availableBinaryFields: Object.keys(item.binary || {}),
        note: 'The binary file must flow into this Code node. Use a Merge node or preserve binary data in the previous node.',
      },
    },
  ];
}

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
const csvText = buffer.toString('utf8');

const rawLines = csvText.split(/\r?\n/);

const lines = rawLines
  .map(line => line.trim())
  .filter(line => line !== '');

// Drop first line: Results
const usefulLines = lines.slice(1);

// Stop at Metadata
const metadataIndex = usefulLines.findIndex(line =>
  line.toLowerCase().startsWith('metadata')
);

const dataSection = metadataIndex >= 0
  ? usefulLines.slice(0, metadataIndex)
  : usefulLines;

if (dataSection.length === 0) {
  return [
    {
      json: {
        success: false,
        message: 'CSV was read, but no usable data section was found.',
        preview: rawLines.slice(0, 10),
      },
    },
  ];
}

const headers = parseCsvLine(dataSection[0]);
const dataRows = dataSection.slice(1);

const output = [];

for (const row of dataRows) {
  const values = parseCsvLine(row);

  const hasData = values.some(value => value !== '');

  if (!hasData) {
    continue;
  }

  const obj = {};

  headers.forEach((header, index) => {
    if (header) {
      obj[header] = values[index] || '';
    }
  });

  output.push({
    json: obj,
  });
}

if (output.length === 0) {
  return [
    {
      json: {
        success: true,
        rowsFound: 0,
        message: 'CSV was read successfully, but there were no prescription rows before the Metadata section.',
        headersFound: headers,
        preview: rawLines.slice(0, 10),
      },
    },
  ];
}

return output;

const centreName = $input.first().json.CentreName || '';

const clinicName = centreName
  .replace(/^Ashley\s*&\s*Martin\s*-\s*/i, '')
  .trim();

return [
  {
    json: {
      ClinicName: clinicName,
    },
  },
];

// n8n Code node
// Name: Check Patient Match
// Mode: Run Once for Each Item

const searchResponse = $json;

// Original CSV / Helix row
const source = $('Loop Over Items').item.json;

const searched = {
  PatientFirstName: source.PatientFirstName || '',
  PatientSurname: source.PatientSurname || '',
  PatientDateOfBirth: source.PatientDateOfBirth || '',
  PatientEmail: source.PatientEmail || '',
  PatientId: source.PatientId || '',
  DrugName: source.DrugName || '',
  CentreName: source.CentreName || '',
};

// Zenoti may return guests directly, or nested depending on response
const guests =
  searchResponse.guests ||
  searchResponse.data?.guests ||
  searchResponse.value ||
  [];

function clean(value) {
  return String(value || '')
    .trim()
    .toLowerCase();
}

function normaliseDate(value) {
  if (!value) return '';

  const raw = String(value).trim();

  // Handles DD/MM/YYYY
  const auMatch = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (auMatch) {
    const [, d, m, y] = auMatch;
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }

  // Handles YYYY-MM-DD or ISO dates
  const isoMatch = raw.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) {
    return `${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}`;
  }

  return clean(raw);
}

const searchedFirst = clean(searched.PatientFirstName);
const searchedLast = clean(searched.PatientSurname);
const searchedDob = normaliseDate(searched.PatientDateOfBirth);
const searchedEmail = clean(searched.PatientEmail);

function getGuestFirstName(guest) {
  return guest.first_name || guest.firstname || guest.firstName || '';
}

function getGuestLastName(guest) {
  return guest.last_name || guest.lastname || guest.lastName || '';
}

function getGuestDob(guest) {
  return (
    guest.date_of_birth ||
    guest.dateOfBirth ||
    guest.dob ||
    guest.birth_date ||
    ''
  );
}

function getGuestEmail(guest) {
  return (
    guest.email ||
    guest.email_address ||
    guest.personal_info?.email ||
    ''
  );
}

function getGuestPhone(guest) {
  return (
    guest.mobile_phone ||
    guest.phone ||
    guest.phone_number ||
    guest.personal_info?.mobile_phone ||
    ''
  );
}

function getGuestCenter(guest) {
  return (
    guest.center_name ||
    guest.center?.name ||
    guest.home_center_name ||
    ''
  );
}

function isPerfectMatch(guest) {
  const guestFirst = clean(getGuestFirstName(guest));
  const guestLast = clean(getGuestLastName(guest));
  const guestDob = normaliseDate(getGuestDob(guest));
  const guestEmail = clean(getGuestEmail(guest));

  const nameMatches =
    guestFirst === searchedFirst &&
    guestLast === searchedLast;

  const dobMatches =
    searchedDob &&
    guestDob &&
    searchedDob === guestDob;

  const emailMatches =
    searchedEmail &&
    guestEmail &&
    searchedEmail === guestEmail;

  // Best rule:
  // exact first name + exact last name + DOB
  // or exact first name + exact last name + email
  return nameMatches && (dobMatches || emailMatches);
}

const perfectMatches = guests.filter(isPerfectMatch);

let matchStatus;
let matchedGuest = null;

if (guests.length === 0) {
  matchStatus = 'NO_MATCH';
} else if (perfectMatches.length === 1) {
  matchStatus = 'PERFECT_MATCH';
  matchedGuest = perfectMatches[0];
} else if (guests.length >= 2) {
  matchStatus = 'MULTIPLE_MATCHES';
} else {
  matchStatus = 'SINGLE_REVIEW';
}

const candidates = guests.map((guest, index) => ({
  row: index + 1,
  zenotiGuestId: guest.id || guest.guest_id || guest.guestId || '',
  firstName: getGuestFirstName(guest),
  lastName: getGuestLastName(guest),
  dob: getGuestDob(guest),
  email: getGuestEmail(guest),
  phone: getGuestPhone(guest),
  center: getGuestCenter(guest),
}));

const candidatesHtmlRows = candidates.map(candidate => `
<tr>
  <td>${candidate.row}</td>
  <td>${candidate.zenotiGuestId}</td>
  <td>${candidate.firstName}</td>
  <td>${candidate.lastName}</td>
  <td>${candidate.dob}</td>
  <td>${candidate.email}</td>
  <td>${candidate.phone}</td>
  <td>${candidate.center}</td>
</tr>
`).join('');

const candidatesHtmlTable = `
<table border="1" cellpadding="6" cellspacing="0">
  <thead>
    <tr>
      <th>#</th>
      <th>Zenoti Guest ID</th>
      <th>First Name</th>
      <th>Last Name</th>
      <th>DOB</th>
      <th>Email</th>
      <th>Phone</th>
      <th>Clinic / Centre</th>
    </tr>
  </thead>
  <tbody>
    ${candidatesHtmlRows || `
      <tr>
        <td colspan="8">No Zenoti guests found</td>
      </tr>
    `}
  </tbody>
</table>
`;

return {
  json: {
    ...source,

    matchStatus,
    matchCount: guests.length,
    perfectMatchCount: perfectMatches.length,

    searchedPatient: searched,

    matchedGuestId: matchedGuest?.id || matchedGuest?.guest_id || matchedGuest?.guestId || '',
    matchedGuest,

    candidates,
    candidatesHtmlTable,

    reviewRequired: matchStatus !== 'PERFECT_MATCH',
  },
};
